<?php
date_default_timezone_set('Asia/Manila');
function stt_nd($v){$v=trim((string)$v);if($v==='')return null;foreach(['m/d/Y','m-d-Y','Y-m-d'] as $f){$d=DateTime::createFromFormat($f,$v);if($d instanceof DateTime)return $d->format('Y-m-d');}$t=strtotime($v);return $t===false?null:date('Y-m-d',$t);}
function stt_fd($v){$t=strtotime((string)$v);return $t===false?'':date('m/d/Y',$t);}
function stt_nextdocval($v){$v=trim((string)$v);if($v===''||!preg_match('/^(STT-)(\d+)$/',$v,$m))return 'STT-0000001';return $m[1].str_pad((string)(((int)$m[2])+1),strlen($m[2]),'0',STR_PAD_LEFT);}
function stt_nextdoc($link){$s=$link->prepare("SELECT docnum FROM tranfile1 WHERE trncde='STT' ORDER BY docnum DESC LIMIT 1");$s->execute();$r=$s->fetch(PDO::FETCH_ASSOC);return stt_nextdocval($r['docnum']??'');}
function stt_userdesc($link,$u){$u=trim((string)$u);if($u==='')return ''; $s=$link->prepare("SELECT userdesc FROM users WHERE usercode=? LIMIT 1");$s->execute([$u]);$r=$s->fetch(PDO::FETCH_ASSOC);return $r['userdesc']??'';}
function stt_itemdesc($link,$i){$s=$link->prepare("SELECT itmdsc FROM itemfile WHERE itmcde=? LIMIT 1");$s->execute([$i]);$r=$s->fetch(PDO::FETCH_ASSOC);return $r['itmdsc']??'';}
function stt_uomdesc($link,$u){$u=trim((string)$u);if($u==='')return '';$s=$link->prepare("SELECT unmdsc FROM itemunitmeasurefile WHERE unmcde=? LIMIT 1");$s->execute([$u]);$r=$s->fetch(PDO::FETCH_ASSOC);return $r['unmdsc']??$u;}
function stt_warehouse_name($link,$w){$w=trim((string)$w);if($w==='')return '';$s=$link->prepare("SELECT warehouse_name FROM warehouse WHERE warcde=? LIMIT 1");$s->execute([$w]);$r=$s->fetch(PDO::FETCH_ASSOC);return $r['warehouse_name']??$w;}
function stt_floor_label($link,$f){$f=trim((string)$f);if($f==='')return '';$s=$link->prepare("SELECT floor_no,floor_name FROM warehouse_floor WHERE warehouse_floor_id=? LIMIT 1");$s->execute([$f]);$r=$s->fetch(PDO::FETCH_ASSOC);if(!$r)return $f;return trim((string)(($r['floor_no']??'')!==''?$r['floor_no']:($r['floor_name']??'')));}
function stt_staff_name($link,$s){$s=trim((string)$s);if($s==='')return '';$q=$link->prepare("SELECT fname,lname FROM warehouse_staff WHERE warehouse_staff_id=? LIMIT 1");$q->execute([$s]);$r=$q->fetch(PDO::FETCH_ASSOC);return trim((string)(($r['fname']??'').' '.($r['lname']??'')));}
function stt_qtylabel($q){$q=(string)(0+(float)$q);return strpos($q,'.')!==false?rtrim(rtrim($q,'0'),'.'):$q;}
function stt_location_label($link,$w,$f){return trim(stt_warehouse_name($link,$w).' + '.stt_floor_label($link,$f));}
function stt_transfer_line_remark($link,$action,$username,$doc,$it,$qty,$uom,$fwa,$ffl,$twa,$tfl,$staff){return $username." ".$action." item '".stt_itemdesc($link,$it)."' qty='".stt_qtylabel($qty)."' uom='".stt_uomdesc($link,$uom)."' in docnum='".$doc."', FROM warehouse: '".stt_location_label($link,$fwa,$ffl)."' TO warehouse: '".stt_location_label($link,$twa,$tfl)."', warehouse staff: '".stt_staff_name($link,$staff)."'";}
function stt_wops($link){$a=[];$s=$link->prepare("SELECT warcde,warehouse_name FROM warehouse ORDER BY warehouse_name ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC))$a[]=$r;return $a;}
function stt_fmap($link){$m=[];$s=$link->prepare("SELECT warehouse_floor_id,warcde,floor_no,floor_name FROM warehouse_floor ORDER BY floor_no ASC,floor_name ASC,warehouse_floor_id ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC)){if(!isset($m[$r['warcde']]))$m[$r['warcde']]=[];$m[$r['warcde']][]=['warehouse_floor_id'=>$r['warehouse_floor_id'],'floor_no'=>trim((string)($r['floor_no']!==''?$r['floor_no']:$r['floor_name']))];}return $m;}
function stt_sops($link){$a=[];$s=$link->prepare("SELECT warehouse_staff_id,fname,lname FROM warehouse_staff ORDER BY fname ASC,lname ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC))$a[]=['warehouse_staff_id'=>$r['warehouse_staff_id'],'staff_name'=>trim($r['fname'].' '.$r['lname'])];return $a;}
function stt_qm($n){return implode(',',array_fill(0,max(0,(int)$n),'?'));}
function stt_curstock($link,$it,$fl,$dt,$ex=[]){$it=trim((string)$it);$fl=trim((string)$fl);$dt=trim((string)$dt);if($it===''||$fl===''||$dt==='')return 0;$sql="SELECT COALESCE(SUM(t2.stkqty),0) current_stock FROM tranfile1 t1 LEFT JOIN tranfile2 t2 ON t1.docnum=t2.docnum WHERE t2.warehouse_floor_id=? AND t1.trndte<=? AND t2.itmcde=?";$p=[$fl,$dt,$it];$ids=[];foreach($ex as $id){$id=(int)$id;if($id>0)$ids[]=$id;}if($ids){$sql.=" AND t2.recid NOT IN (".stt_qm(count($ids)).")";$p=array_merge($p,$ids);} $s=$link->prepare($sql);$s->execute($p);$r=$s->fetch(PDO::FETCH_ASSOC);return (float)($r['current_stock']??0);}
function stt_uom_options($link){$a=[];$s=$link->prepare("SELECT unmcde,unmdsc FROM itemunitmeasurefile ORDER BY unmdsc ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC))$a[]=['unmcde'=>$r['unmcde'],'unmdsc'=>$r['unmdsc']];return $a;}
function stt_default_uom($uom_options){foreach($uom_options as $o){if(strtolower(trim($o['unmdsc']))==='pcs'||strtolower(trim($o['unmcde']))==='pcs')return $o['unmcde'];}return !empty($uom_options)?$uom_options[0]['unmcde']:'';}
function stt_get_conversion($link,$it,$um){$it=trim((string)$it);$um=trim((string)$um);if($it===''||$um==='')return 1;if(strtolower($um)==='pcs')return 1;$s=$link->prepare("SELECT conversion FROM itemunitfile WHERE itmcde=? AND unmcde=? LIMIT 1");$s->execute([$it,$um]);$r=$s->fetch(PDO::FETCH_ASSOC);return ($r&&$r['conversion']!==null&&$r['conversion']!=='')?(float)$r['conversion']:1;}
function stt_get_item_uoms($link,$it){$it=trim((string)$it);if($it==='')return [];$a=[];$s=$link->prepare("SELECT iuf.unmcde,iuf.conversion,iumf.unmdsc FROM itemunitfile iuf LEFT JOIN itemunitmeasurefile iumf ON iuf.unmcde=iumf.unmcde WHERE iuf.itmcde=? ORDER BY iumf.unmdsc ASC");$s->execute([$it]);while($r=$s->fetch(PDO::FETCH_ASSOC)){$u=trim((string)($r['unmcde']??''));if($u==='')continue;$a[]=['unmcde'=>$u,'unmdsc'=>!empty($r['unmdsc'])?trim((string)$r['unmdsc']):$u,'conversion'=>$r['conversion']];}return $a;}
function stt_header($link,$doc){$s=$link->prepare("SELECT * FROM tranfile1 WHERE docnum=? AND trncde='STT' LIMIT 1");$s->execute([$doc]);return $s->fetch(PDO::FETCH_ASSOC);} 
function stt_savehead($link,$doc,$dt,$ord,$rem,$user){$h=stt_header($link,$doc);$u=trim((string)($h['usercode']??''));if($u==='')$u=trim((string)$user);$d=['docnum'=>$doc,'cuscde'=>null,'trntot'=>0,'trndte'=>$dt,'ordernum'=>$ord,'remarks'=>$rem,'usercode'=>$u,'trncde'=>'STT'];if(empty($h))PDO_InsertRecord($link,'tranfile1',$d,false);else{unset($d['docnum']);PDO_UpdateRecord($link,'tranfile1',$d,'recid = ?',[$h['recid']],false);} $s=$link->prepare("UPDATE tranfile2 SET trndte=?,trncde='STT',untprc=0,extprc=0 WHERE docnum=?");$s->execute([$dt,$doc]);}
function stt_linepair($link,$doc,$dt,$it,$qty,$fwa,$ffl,$twa,$tfl,$staff,$unmcde='',$batch=''){if($batch==='')$batch='STTLINE-'.date('YmdHis').'-'.mt_rand(1000,9999);$conversion=stt_get_conversion($link,$it,$unmcde);$stkqty=abs((float)$qty)*$conversion;$c=['docnum'=>$doc,'trncde'=>'STT','trndte'=>$dt,'itmcde'=>$it,'itmqty'=>(float)$qty,'unmcde'=>$unmcde,'untprc'=>0,'extprc'=>0,'file_batchno'=>$batch,'warehouse_staff_id'=>$staff];$a=$c;$a['stkqty']=-1*$stkqty;$a['warcde']=$fwa;$a['warehouse_floor_id']=$ffl;$b=$c;$b['stkqty']=$stkqty;$b['warcde']=$twa;$b['warehouse_floor_id']=$tfl;PDO_InsertRecord($link,'tranfile2',$a,false);PDO_InsertRecord($link,'tranfile2',$b,false);} 
function stt_rows($link,$doc){$sql="SELECT t.recid,t.itmcde,t.itmqty,t.stkqty,t.unmcde,t.warcde,t.warehouse_floor_id,t.warehouse_staff_id,t.file_batchno,i.itmdsc,w.warehouse_name,f.floor_no,f.floor_name,ws.fname,ws.lname,iumf.unmdsc FROM tranfile2 t LEFT JOIN itemfile i ON i.itmcde=t.itmcde LEFT JOIN warehouse w ON w.warcde=t.warcde LEFT JOIN warehouse_floor f ON f.warehouse_floor_id=t.warehouse_floor_id LEFT JOIN warehouse_staff ws ON ws.warehouse_staff_id=t.warehouse_staff_id LEFT JOIN itemunitmeasurefile iumf ON iumf.unmcde=t.unmcde WHERE t.docnum=? AND t.trncde='STT' ORDER BY t.file_batchno ASC,t.recid ASC";$s=$link->prepare($sql);$s->execute([$doc]);return $s->fetchAll(PDO::FETCH_ASSOC);} 
