function stt_render($lines){if(!$lines)return ['html'=>"<tr><td colspan='8' class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>",'html_mobile'=>"<tr><td class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>"]; $h="<tr><th>Item</th><th style='text-align:right'>Quantity</th><th>UOM</th><th>Warehouse From</th><th>Floor From</th><th>Warehouse To</th><th>Floor To</th><th class='text-center'>Action</th></tr>";$m='';foreach($lines as $l){$h.="<tr><td>".htmlspecialchars((string)$l['item_desc'],ENT_QUOTES)."</td><td style='text-align:right'>".number_format((float)$l['qty'],2)."</td><td>".htmlspecialchars((string)$l['uom'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_from'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_floor_from'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_to'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_floor_to'],ENT_QUOTES)."</td><td class='text-center'><div class='d-grid gap-2'><button type='button' class='btn btn-primary btn-sm fw-bold' onclick='salesfile2(\"getEdit\",{$l['recid']})'>View</button><button type='button' class='btn btn-danger btn-sm fw-bold' onclick='salesfile2(\"delete\",{$l['recid']})'>Delete</button></div></td></tr>"; $m.="<tr><td><div class='card shadow-sm border-0 mb-3'><div class='card-body'><div class='fw-bold mb-2'>".htmlspecialchars((string)$l['item_desc'],ENT_QUOTES)."</div><div><span class='fw-bold'>Quantity:</span> ".number_format((float)$l['qty'],2)." ".htmlspecialchars((string)$l['uom'],ENT_QUOTES)."</div><div><span class='fw-bold'>Warehouse From:</span> ".htmlspecialchars((string)$l['warehouse_from'],ENT_QUOTES)."</div><div><span class='fw-bold'>Floor From:</span> ".htmlspecialchars((string)$l['warehouse_floor_from'],ENT_QUOTES)."</div><div><span class='fw-bold'>Warehouse To:</span> ".htmlspecialchars((string)$l['warehouse_to'],ENT_QUOTES)."</div><div><span class='fw-bold'>Floor To:</span> ".htmlspecialch