<script>
var ajaxUrl='stock_transfer_transaction_file2.php',floorMap=<?php echo json_encode($warehouse_floor_map); ?>,defaultUomCode='<?php echo addslashes($default_uom_code); ?>',baseUomDisplay='<?php echo addslashes($base_uom_display); ?>';
function post(d,cb){d.stt_ajax='1';$.ajax({data:d,dataType:'json',type:'post',url:ajaxUrl,success:cb});}
function floors(id,w,s){var $x=$('#'+id),o="<option value=''>Select Warehouse Floor</option>",a=floorMap[w]||[];for(var i=0;i<a.length;i++){o+="<option value='"+a[i].warehouse_floor_id+"'"+((s&&s===a[i].warehouse_floor_id)?' selected':'')+">"+a[i].floor_no+"</option>";}$x.html(o);}
function stocktxt(m,v){v=parseFloat(v);if(isNaN(v))v=0;$('#current_stock_'+m+'_text').text('Current Stock: '+v.toFixed(2)+' '+baseUomDisplay);}
function resetUomLabels(sel){$(sel).find('option').each(function(){var lbl=$(this).data('default-label');if(typeof lbl!=='undefined')$(this).text(lbl);$(this).show();});}
function applyUomLabels(sel,uoms,filter){resetUomLabels(sel);var m={};if(uoms&&uoms.length){for(var i=0;i<uoms.length;i++){if(uoms[i]&&uoms[i].unmcde)m[uoms[i].unmcde]=uoms[i];}}$(sel).data('uom-map',m);$(sel).find('option').each(function(){var v=$(this).val(),lbl=$(this).data('default-label');if(typeof lbl==='undefined'||v==='')return;if(filter){if(v===defaultUomCode){$(this).show();}else if(!m[v]){$(this).hide();return;}else{$(this).show();}}if(m[v]&&m[v].conversion!==null&&m[v].conversion!==''){var c=Number(m[v].conversion);if(isFinite(c))$(this).text(lbl+' ('+c+' '+baseUomDisplay+')');}});}
function updateUomDropdown(sel,itmcde,selected,preserve,lockDisabled){var $s=$(sel),strictEditSelection=preserve===true,shouldLockDisabled=lockDisabled===true,normalizedSelected=$.trim(selected||'');$s.data('current-itmcde',itmcde||'');$s.data('uom-map',{});resetUomLabels(sel);$s.find('option').show();if(typeof selected!=='undefined')$s.val(strictEditSelection?normalizedSelected:(normalizedSelected||defaultUomCode||''));else $s.val(defaultUomCode||'');$s.prop('disabled',shouldLockDisabled||!itmcde);if(!itmcde)return;post({event_action:'get_item_uoms',itmcde:itmcde},function(r){if($s.data('current-itmcde')!==itmcde)return;var uoms=r.uoms||[];applyUomLabels(sel,uoms,true);var fv='';if(strictEditSelection){$s.find('option').each(function(){if($.trim($(this).val())===normalizedSelected){fv=normalizedSelected;return false;}});}else{$s.find('option:visible').each(function(){if($(this).val()!==''){fv=$(this).val();return false;}});} var finalUomCode=strictEditSelection?fv:(fv||defaultUomCode||'');$s.find('option').prop('selected',false);(strictEditSelection?$s.find('option'):$s.find('option:visible')).each(function(){if($.trim($(this).val())=== $.trim(finalUomCode)){$(this).prop('selected',true);return false;}});if(finalUomCode!=='')$s.val(finalUomCode).trigger('change');$s.prop('disabled',shouldLockDisabled);});}
function parseNumericValue(v){var n=parseFloat(String(v||'0').replace(/,/g,''));return isNaN(n)?0:n;}
function normalizeUomCode(v){return $.trim(String(v||'')).toLowerCase();}
function getTodayDate(){var d=new Date(),m=(d.getMonth()+1),dy=d.getDate(),y=d.getFullYear();return (m<10?'0'+m:m)+'/'+(dy<10?'0'+dy:dy)+'/'+y;}
function refresh(m,cb){var it=$('#itmcde_'+m+'_hidden').val(),fl=$('#warehouse_floor_id_from_'+m).val(),dt=getTodayDate();if(!it||!fl){stocktxt(m,0);if(cb)cb(0);return;} post({event_action:'get_current_stock',item_code:it,warehouse_floor_id:fl,trndte:dt},function(r){var currentStock=parseNumericValue(r.current_stock);stocktxt(m,currentStock);if(cb)cb(currentStock);});}
function strip(x){return $('<div>').html(x||'').text();}
function modalErrorSelector(m){return m==='edit'?'.error_msg_edit_modal':'.error_msg_add_modal';}
function showModalError(m,msg){$(modalErrorSelector(m)).html("<div class='alert alert-danger m-2' role='alert'>"+msg+"</div>");}
function showModalErrors(m,errors){if(!errors||!errors.length){clearModalError(m);return;} var html="<div class='alert alert-danger m-2' role='alert'>";for(var i=0;i<errors.length;i++){html+="<div>"+errors[i]+"</div>";}html+="</div>";$(modalErrorSelector(m)).html(html);}
function clearModalError(m){$(modalErrorSelector(m)).html('');}
function collectValidationErrors(m){var errors=[],it=$('#itmcde_'+m+'_hidden').val(),q=parseNumericValue($('#itmqty_'+m).val()),uom=$('#unmcde_'+m).val(),fwa=$('#warcde_from_'+m).val(),ffl=$('#warehouse_floor_id_from_'+m).val(),twa=$('#warcde_to_'+m).val(),tfl=$('#warehouse_floor_id_to_'+m).val(),staff=$('#warehouse_staff_id_'+m).val();if(!it)errors.push('<b>Item</b> is required.');if(q<=0)errors.push('<b>Quantity</b> is required.');if(!uom)errors.push('<b>Unit of Measure</b> is required.');if(!fwa)errors.push('<b>Warehouse From</b> is required.');if(!ffl)errors.push('<b>Warehouse Floor From</b> is required.');if(!twa)errors.push('<b>Warehouse To</b> is required.');if(!tfl)errors.push('<b>Warehouse Floor To</b> is required.');if(!staff)errors.push('<b>Warehouse Staff</b> is required.');if(ffl&&tfl&&ffl===tfl)errors.push('<b>Warehouse Floor From</b> and <b>Warehouse Floor To</b> cannot be the same.');return errors;}
function uomConversion(m){var code=$('#unmcde_'+m).val()||'',map=$('#unmcde_'+m).data('uom-map')||{},row=map[code],conversion=1;if(normalizeUomCode(code)!==normalizeUomCode(defaultUomCode)&&row&&row.conversion!==null&&row.conversion!==''){conversion=parseNumericValue(row.conversion);if(!isFinite(conversion)||conversion<=0)conversion=1;} return conversion;}
function requiredBaseQty(m){return parseNumericValue($('#itmqty_'+m).val())*uomConversion(m);}
function validate(m,cb){var errors=collectValidationErrors(m);if(errors.length){showModalErrors(m,errors);cb(false);return;} if(m==='edit'){cb(true);return;} refresh(m,function(availableBaseQty){var requiredQty=requiredBaseQty(m);if(requiredQty>(parseNumericValue(availableBaseQty)+0.0000001)){showModalErrors(m,['Insufficient quantity in selected warehouse.']);cb(false);return;} clearModalError(m);cb(true);});}
function loadrows(){post({event_action:'load_rows',docnum:$('#docnum_hidden').val()},function(r){$('#tbody_main').html(r.html||'');$('#tbody_main_mobile').html(r.html_mobile||'');});}
function back_page(){document.forms.myforms.target='_self';document.forms.myforms.method='post';document.forms.myforms.action='stock_transfer_transaction.php';document.forms.myforms.submit();}
function clearadd(){$('#itmcde_add').prop('readonly',false).val('');$('#itmcde_add_hidden').val('');$('#itmqty_add').val('');$('#unmcde_add').data('uom-map',{}).val(defaultUomCode).prop('disabled',true);resetUomLabels('#unmcde_add');$('#warcde_from_add,#warcde_to_add,#warehouse_staff_id_add').val('');floors('warehouse_floor_id_from_add','','');floors('warehouse_floor_id_to_add','','');stocktxt('add',0);clearModalError('add');}
function select_item_modal(code,desc,m){if(m==='add'){$('#itmcde_add_hidden').val(code);$('#itmcde_add').val(desc).prop('readonly',true);$('#unmcde_add').prop('disabled',false);$('#view_itm_search').modal('hide');$('#insert_modal_sales').modal('show');updateUomDropdown('#unmcde_add',code,$('#unmcde_add').val()||defaultUomCode);refresh('add');clearModalError('add');}else{$('#itmcde_edit_hidden').val(code);$('#itmcde_edit').val(desc);$('#view_itm_search').modal('hide');$('#edit_modal_sales').modal('show');updateUomDropdown('#unmcde_edit',code,$('#unmcde_edit').val()||defaultUomCode,false,true);refresh('edit');clearModalError('edit');} $('.error_msg_itm_view').html('');}
function back_from_view_func(m){$('#view_itm_search').modal('hide');if(m==='add')$('#insert_modal_sales').modal('show');else $('#edit_modal_sales').modal('show');}
function search_itm_func(m){var q=m==='add'?$('#itmcde_add').val():$('#itmcde_edit').val();$('#xevent_itmsearch_hidden').val(m);$('.back_btn_modal_footer').html("<button type='button' class='btn btn-danger' onclick='back_from_view_func("+JSON.stringify(m)+")'>Back</button>");post({event_action:'search_itm',search_itm:q,event_action_itmsearch:m},function(r){if(r.status===0){var h="<div class='alert alert-danger m-2' role='alert'>"+r.msg+"</div>";if(m==='add')$('.error_msg_add_modal').html(h);else $('.error_msg_edit_modal').html(h);return;} $('.html_itm_view_data').html(r.html||'');$('#itm_view').val(r.itm_search||'');$('.error_msg_itm_view').html('');if(m==='add')$('#insert_modal_sales').modal('hide');else $('#edit_modal_sales').modal('hide');$('#view_itm_search').modal('show');});}
function search_itm_func_inmodal(){post({event_action:'search_itm',search_itm:$('#itm_view').val(),event_action_itmsearch:$('#xevent_itmsearch_hidden').val()||'add'},function(r){if(r.status===0){$('.error_msg_itm_view').html("<div class='alert alert-danger m-2' role='alert'>"+r.msg+"</div>");return;} $('.html_itm_view_data').html(r.html||'');$('.error_msg_itm_view').html('');});}
function handle(ev,r){if(r.status===0){if(ev==='insert')showModalError('add',r.msg);else if(ev==='submitEdit')showModalError('edit',r.msg);else{$('#alert_modal_body_system').html(r.msg);$('#alert_modal_system').modal('show');}return;} if(r.msg==='save_exit'){back_page();return;} if(r.msg==='save_new'){$('#docnum_1,#docnum_hidden').val(r.new_docnum||'');$('#ordernum_1').val('');$('#remarks_1').val('');$('#tbody_main').html("<tr><td colspan='8' class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>");$('#tbody_main_mobile').html("<tr><td class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>");return;} if(r.msg==='retEdit'){$('#salesfile2_recid_hidden').val(r.retEdit.recid||'');$('#itmcde_edit_hidden').val(r.retEdit.itmcde||'');$('#itmcde_edit').val(r.retEdit.itmdsc||'');$('#itmqty_edit').val(r.retEdit.itmqty||'');$('#unmcde_edit').val(r.retEdit.unmcde||'');updateUomDropdown('#unmcde_edit',r.retEdit.itmcde||'',r.retEdit.unmcde,true,true);$('#warcde_from_edit').val(r.retEdit.warcde_from||'');floors('warehouse_floor_id_from_edit',r.retEdit.warcde_from||'',r.retEdit.warehouse_floor_id_from||'');$('#warcde_to_edit').val(r.retEdit.warcde_to||'');floors('warehouse_floor_id_to_edit',r.retEdit.warcde_to||'',r.retEdit.warehouse_floor_id_to||'');$('#warehouse_staff_id_edit').val(r.retEdit.warehouse_staff_id||'');stocktxt('edit',r.retEdit.current_stock||0);clearModalError('edit');$('#edit_modal_sales').modal('show');return;} if(ev==='insert'){$('#insert_modal_sales').modal('hide');clearModalError('add');} if(ev==='submitEdit'){$('#edit_modal_sales').modal('hide');clearModalError('edit');} if(r.html!==undefined){$('#tbody_main').html(r.html||'');$('#tbody_main_mobile').html(r.html_mobile||'');}}
function salesfile2(ev,id){var doc=$('#docnum_hidden').val();if(ev==='open_add'){clearadd();$('#insert_modal_sales').modal('show');return;} if(ev==='getEdit'){post({event_action:'getEdit',docnum:doc,recid:id},function(r){handle(ev,r);});return;} if(ev==='delete'){if(!confirm('Are you sure you want to delete?'))return;post({event_action:'delete',docnum:doc,recid:id},function(r){handle(ev,r);});return;} if(ev==='save_exit'||ev==='save_new'){post({event_action:ev,docnum:doc,docnum_1:$('#docnum_1').val(),trndte_1:$('#trndte_1').val(),ordernum_1:$('#ordernum_1').val(),remarks_1:$('#remarks_1').val(),usercode_1:$('#usercode_1').val()},function(r){handle(ev,r);});return;} if(ev==='insert'||ev==='submitEdit'){var m=ev==='insert'?'add':'edit';validate(m,function(ok){if(!ok)return;var p={event_action:ev,docnum:doc,docnum_1:$('#docnum_1').val(),trndte_1:$('#trndte_1').val(),ordernum_1:$('#ordernum_1').val(),remarks_1:$('#remarks_1').val(),usercode_1:$('#usercode_1').val()}; if(m==='add'){$.extend(p,{itmcde_add_hidden:$('#itmcde_add_hidden').val(),itmqty_add:$('#itmqty_add').val(),unmcde_add:$('#unmcde_add').val(),warcde_from_add:$('#warcde_from_add').val(),warehouse_floor_id_from_add:$('#warehouse_floor_id_from_add').val(),warcde_to_add:$('#warcde_to_add').val(),warehouse_floor_id_to_add:$('#warehouse_floor_id_to_add').val(),warehouse_staff_id_add:$('#warehouse_staff_id_add').val()});}else{$.extend(p,{recid:$('#salesfile2_recid_hidden').val(),itmcde_edit_hidden:$('#itmcde_edit_hidden').val(),itmqty_edit:$('#itmqty_edit').val(),unmcde_edit:$('#unmcde_edit').val(),warcde_from_edit:$('#warcde_from_edit').val(),warehouse_floor_id_from_edit:$('#warehouse_floor_id_from_edit').val(),warcde_to_edit:$('#warcde_to_edit').val(),warehouse_floor_id_to_edit:$('#warehouse_floor_id_to_edit').val(),warehouse_staff_id_edit:$('#warehouse_staff_id_edit').val()});} post(p,function(r){handle(ev,r);});});}}
$(function(){loadrows();$('#warcde_from_add').on('change',function(){floors('warehouse_floor_id_from_add',$(this).val(),'');refresh('add');});$('#warcde_to_add').on('change',function(){floors('warehouse_floor_id_to_add',$(this).val(),'');});$('#warehouse_floor_id_from_add').on('change',function(){refresh('add');});$('#warcde_from_edit').on('change',function(){floors('warehouse_floor_id_from_edit',$(this).val(),'');refresh('edit');});$('#warcde_to_edit').on('change',function(){floors('warehouse_floor_id_to_edit',$(this).val(),'');});$('#warehouse_floor_id_from_edit').on('change',function(){refresh('edit');});$('#trndte_1').on('change',function(){refresh('add');refresh('edit');});$('#itm_view').on('keypress',function(e){if(e.key==='Enter'||e.keyCode===13){e.preventDefault();search_itm_func_inmodal();}});$('#itmcde_add').on('keypress',function(e){if(e.key==='Enter'||e.keyCode===13){e.preventDefault();search_itm_func('add');}});});
</script>
